SELECT *
FROM foreign_birth_statistic
WHERE foreign_born_population > 50000;

SELECT year, region, foreign_born_population
FROM population_data
WHERE year = 2000 AND region = 'England';

SELECT year, region, census_year
FROM years
WHERE year_id > 20 AND region IN ('England', 'Wales');

SELECT year, region, 
       (foreign_born_population / total_population) * 100 AS percentage_foreign_born 
FROM population_data;

SELECT y.year, p.year_id, p.percentage_foreign_born
FROM population_data AS p
JOIN years AS y ON p.year_id = y.year_id;

SELECT irp.irish_born_population, y.year 
FROM irish_population irp
JOIN years y ON irp.year_id = y.year_id;

SELECT category_name, MAX(last_updated) AS latest_update
FROM demographic_categories
GROUP BY category_name;
